const results   = $input.all();
const dateLabel = results[0]?.json?.dateLabel || 'yesterday';

const COMPANIES = new Set([
  'cb5b45d3-67ce-46ce-bfe8-3e2e70bdd2f3',
  '45385e29-2383-4e75-9bd5-50fb9ec4db3b',
  '1450d9df-b724-4cfb-ba0b-6391070af4d8',
]);

function pct(num, den) {
  if (!den) return '0.00%';
  return (num / den * 100).toFixed(2) + '%';
}

const COL = { name: 26, leads: 5, replies: 7, positive: 8, rr: 10, pr: 9 };

function hdr() {
  return [
    'Campaign'.padEnd(COL.name),
    'Leads'.padStart(COL.leads),
    'Replies'.padStart(COL.replies),
    'Positive'.padStart(COL.positive),
    'Reply Rate'.padStart(COL.rr),
    'Pos Rate'.padStart(COL.pr),
  ].join(' | ');
}

function sep() { return '-'.repeat(hdr().length); }

function row(name, leads, replies, positive, rr, pr) {
  const n = name.length > COL.name ? name.slice(0, COL.name - 3) + '...' : name.padEnd(COL.name);
  return [
    n,
    String(leads).padStart(COL.leads),
    String(replies).padStart(COL.replies),
    String(positive).padStart(COL.positive),
    String(rr).padStart(COL.rr),
    String(pr).padStart(COL.pr),
  ].join(' | ');
}

function table(dataRows) {
  if (!dataRows.length) return '_No activity_';
  return ['```', hdr(), sep(), ...dataRows, '```'].join('\n');
}

// Accumulators
const agg = {
  co: { yday_leads: 0, yday_replies: 0, yday_positive: 0, at_leads: 0, at_replies: 0, at_positive: 0 },
  pe: { yday_leads: 0, yday_replies: 0, yday_positive: 0, at_leads: 0, at_replies: 0, at_positive: 0 },
};

let grandLeads = 0, grandYday = 0, grandAllTime = 0;
const coRows = [], peRows = [];

for (const item of results) {
  const r    = item.json;
  const isCo = COMPANIES.has(r.campaignId);
  const g    = isCo ? agg.co : agg.pe;

  g.yday_leads    += r.uniqueCount        || 0;
  g.yday_replies  += r.yday_replies       || 0;
  g.yday_positive += r.yday_positive      || 0;
  g.at_leads      += r.allTimeUniqueCount || 0;
  g.at_replies    += r.alltime_replies    || 0;
  g.at_positive   += r.alltime_positive   || 0;

  grandLeads   += r.totalLeads        || 0;
  grandYday    += r.uniqueCount       || 0;
  grandAllTime += r.allTimeUniqueCount || 0;

  (isCo ? coRows : peRows).push(r);
}

const { co, pe } = agg;

// Summary tables — skip group row if Leads == 0
function summaryTable(ydayOrAt) {
  const isYday = ydayOrAt === 'yday';
  const rows = [];
  if (isYday) {
    if (co.yday_leads > 0) rows.push(row('Companies', co.yday_leads, co.yday_replies, co.yday_positive, pct(co.yday_replies, co.yday_leads), pct(co.yday_positive, co.yday_leads)));
    if (pe.yday_leads > 0) rows.push(row('People',    pe.yday_leads, pe.yday_replies, pe.yday_positive, pct(pe.yday_replies, pe.yday_leads), pct(pe.yday_positive, pe.yday_leads)));
  } else {
    if (co.at_leads > 0) rows.push(row('Companies', co.at_leads, co.at_replies, co.at_positive, pct(co.at_replies, co.at_leads), pct(co.at_positive, co.at_leads)));
    if (pe.at_leads > 0) rows.push(row('People',    pe.at_leads, pe.at_replies, pe.at_positive, pct(pe.at_replies, pe.at_leads), pct(pe.at_positive, pe.at_leads)));
  }
  return table(rows);
}

// Per-campaign tables — skip row if Leads == 0
function campaignTable(rows, type) {
  const isYday = type === 'yday';
  const filtered = rows.filter(r => isYday ? (r.uniqueCount || 0) > 0 : (r.allTimeUniqueCount || 0) > 0);
  return table(filtered.map(r => isYday
    ? row(r.campaignName, r.uniqueCount,        r.yday_replies,    r.yday_positive,    r.yday_reply_rate,    r.yday_positive_rate)
    : row(r.campaignName, r.allTimeUniqueCount, r.alltime_replies, r.alltime_positive, r.alltime_reply_rate, r.alltime_positive_rate)
  ));
}

const text = [
  `:bar_chart: *Instantly Daily Report \u2013 ${dateLabel}*`,
  '',
  `*Yesterday Summary*`,
  summaryTable('yday'),
  '',
  `*All-time Summary*`,
  summaryTable('alltime'),
  '',
  `*Yesterday \u2013 Companies*`,
  campaignTable(coRows, 'yday'),
  '',
  `*Yesterday \u2013 People*`,
  campaignTable(peRows, 'yday'),
  '',
  `*All-time \u2013 Companies*`,
  campaignTable(coRows, 'alltime'),
  '',
  `*All-time \u2013 People*`,
  campaignTable(peRows, 'alltime'),
  '',
  `_Total: ${grandLeads} leads | Yesterday: ${grandYday} unique | All-time: ${grandAllTime} unique_`,
].join('\n');

return [{ json: { text, dateLabel } }];
